    sha256 "a69e617ef92b554c5d14d9978e1dcc6a1f4e59ed9e85591f6298d488778f99e7"
  end

  on_linux do
    if Hardware::CPU.intel? && Hardware::CPU.is_64_bit?
      url "https://github.com/candelahq/candela/releases/download/v0.3.0/candela_0.3.0_Linux_amd64.tar.gz"
      sha256 "78bfee7afb199fd21841fed4263777cc29ede13fcc74a9ca5082f500a1cbc93f"
    elsif Hardware::CPU.arm? && Hardware::CPU.is_64_bit?
      url "https://github.com/candelahq/candela/releases/download/v0.3.0/candela_0.3.0_Linux_arm64.tar.gz"
      sha256 "89c3901e0ac48a798a7a993f2ed69218f4425bed1e6528fc2bf94f4d2f9d5c97"
    end
  end

  def install
    bin.install "candela"
  end

  def caveats
    <<~EOS
      To get started, create a config file:

        mkdir -p ~/.config/candela
        cat > ~/.config/candela/config.yaml <<EOF
        port: 8181
        providers:
          - name: google
            models: ["gemini-2.5-pro", "gemini-2.5-flash"]
        vertex_ai:
          project: YOUR_GCP_PROJECT
          region: us-central1
        EOF

      Then run:
        candela start          # background daemon
        candela status         # check running state
        candela run            # foreground (debug)

      Management UI: http://127.0.0.1:8181/_local/

      Or as a login service:
        brew services start candela
    EOS
  end

  service do
    run [opt_bin/"candela", "run"]
    keep_alive true
    log_path var/"log/candela.log"
    error_log_path var/"log/candela.log"
